			topological_order.push_back(from);

			REP(i, output[from].size()) {

				edge &e = output[from][i];

				if (e.need) {

					input[e.dest]--;

					if (input[e.dest] == 0) st.push(e.dest);

				}

			}

		}



		bool valid = true;

		REP(i, N) if (input[i] > 0) valid = false;

		return valid;

	}

};



